/****
 * =CQP_MAXIMUM_INVENTORIES_USD * CQP_MAXIMUM_INVENTORIES_GROSS_RATE
 * By Adriana Centellas
 */

function safeNumber(v) {
  if (typeof v !== "string" && typeof v !== "number") return 0;

  const normalized = String(v).replace(/,/g, "");
  const n = Number(normalized);

  return Number.isNaN(n) ? 0 : n;
}

return safeNumber(this.CQP_MAXIMUM_INVENTORIES_USD) * safeNumber((safeNumber(this.CQP_MAXIMUM_INVENTORIES_GROSS_RATE)/100));

/******
 * =((CQP_MAXIMUM_INVENTORIES_USD/CQP_MAXIMUM_INVENTORIES_HISTORICAL_TERMS)-1)*100
 * By Adriana Centellas
 * Edited By Natalia Mendez
 */

// Convert any value to a safe number
function safeNumber(v) {
  if (typeof v !== "string" && typeof v !== "number") return 0;

  const normalized = String(v).replace(/,/g, "");
  const n = Number(normalized);

  return Number.isNaN(n) ? 0 : n;
}

// Ensure numeric values
let inventoriesUsd = safeNumber(this.CQP_MAXIMUM_INVENTORIES_USD);
let inventoriesHistorical = safeNumber(this.CQP_MAXIMUM_INVENTORIES_HISTORICAL_TERMS);

// Main calculation
var returnVar = (inventoriesHistorical !== 0 && inventoriesUsd !== 0)
  ? ((inventoriesUsd / inventoriesHistorical) - 1) * 100
  : 0;


// Remove classes first
setTimeout(function () {
  const inputSelector = $('[selector="CQP_MAXIMUM_INVENTORIES_VARIATION"] > div > input');
  inputSelector.removeClass('inputError inputOk');
}, 200);


// Only evaluate color if result is a valid number and not zero
if (!Number.isNaN(returnVar) && returnVar !== 0) {

  let valor = parseFloat(returnVar);

  setTimeout(function () {
    const inputSelector = $('[selector="CQP_MAXIMUM_INVENTORIES_VARIATION"] > div > input');
    inputSelector.removeClass('inputError inputOk');

    if (valor < 0) {
      inputSelector.addClass('inputError'); // red
    } else if (valor > 0) {
      inputSelector.addClass('inputOk'); // green
    }

  }, 500);
}

return returnVar;

