/*
* Plain validation that checks inventory fields only if CQP_STORAGE_FILLED is true.
* Ensures that CQP_MAXIMUM_INVENTORIES_USD, CQP_AVERAGE_INVENTORIES_USD,
* CQP_MAXIMUM_INVENTORIES_GROSS_RATE, and CQP_AVERAGE_INVENTORIES_GROSS_RATE 
* are not empty, null, or zero.
*
* @param none
* @return (Object) { valid: Boolean, message: String }
*
* by Adriana Centellas
* Edited By Natalia Mendez
*/

let result = { valid: true, message: "" };

//If user wants to go back on the process the required values are now non required
if (this.CQP_SUBMIT != "BACK") {

  // --- Run validation only if condition is met -------------------------
  if (this._parent.CQP_STORAGE_FILLED === true) {

  if (
    this.CQP_MAXIMUM_INVENTORIES_USD === null ||
    this.CQP_MAXIMUM_INVENTORIES_USD === "" ||
    parseFloat(this.CQP_MAXIMUM_INVENTORIES_USD) === 0 ||
    isNaN(parseFloat(this.CQP_MAXIMUM_INVENTORIES_USD)) ||

    this.CQP_AVERAGE_INVENTORIES_USD === null ||
    this.CQP_AVERAGE_INVENTORIES_USD === "" ||
    parseFloat(this.CQP_AVERAGE_INVENTORIES_USD) === 0 ||
    isNaN(parseFloat(this.CQP_AVERAGE_INVENTORIES_USD))

  /* ||  this.CQP_MAXIMUM_INVENTORIES_GROSS_RATE === null ||
    this.CQP_MAXIMUM_INVENTORIES_GROSS_RATE === "" ||
    parseFloat(this.CQP_MAXIMUM_INVENTORIES_GROSS_RATE) === 0 ||
    isNaN(parseFloat(this.CQP_MAXIMUM_INVENTORIES_GROSS_RATE)) ||

    this.CQP_AVERAGE_INVENTORIES_GROSS_RATE === null ||
    this.CQP_AVERAGE_INVENTORIES_GROSS_RATE === "" ||
    parseFloat(this.CQP_AVERAGE_INVENTORIES_GROSS_RATE) === 0 ||
    isNaN(parseFloat(this.CQP_AVERAGE_INVENTORIES_GROSS_RATE))*/
  ) {
    result.valid = false;
    result.message = `All inventory fields must have valid values (cannot be empty, null, or 0).`;
  }
}
} else {
    result.valid = true;
    result.message = ``;
}

return result;

/*
* Plain validation that ensures exactly one of CQP_SELECTED_STORAGE_MAX 
* or CQP_SELECTED_STORAGE_AVE is true (never both or neither).
*
* @param none
* @return (Object) { valid: Boolean, message: String }
*
* by Adriana Centellas
* Edited By Natalia Mendez
*/

let result = { valid: true, message: "" };

//If user wants to go back on the process the required values are now non required
if (this.CQP_SUBMIT !== "BACK") {
    // --- Validation rule -------------------------------------------------
  if (
    (this.CQP_SELECTED_STORAGE_MAX === true && this.CQP_SELECTED_STORAGE_AVE === true) ||
    (this.CQP_SELECTED_STORAGE_MAX === false && this.CQP_SELECTED_STORAGE_AVE === false)
  ) {
    result.valid = false;
    result.message = `You must select only one option: either Maximum Storage or Average Storage, not both or none.`;
  }
} else {
    result.valid = true;
    result.message = ``;
}

// --- Return object result --------------------------------------------
return result;

/******
 * CQP_TOTAL_INVENTORIES_GWP
 * Summatory of AVERAGE and MAXIMUM
 */

function safeNumber(v) {
  if (typeof v !== "string" && typeof v !== "number") return 0;

  const normalized = String(v).replace(/,/g, "");
  const n = Number(normalized);

  return Number.isNaN(n) ? 0 : n;
}

if (this.CQP_SELECTED_STORAGE_MAX) {
    return safeNumber(this.CQP_MAXIMUM_INVENTORIES_GWP);
} 
if (this.CQP_SELECTED_STORAGE_AVE) {
    return safeNumber(this.CQP_AVERAGE_INVENTORIES_GWP);
}

/*******
 * Get percentage from CQP_COMMODITIES based on TOTAL_IMPORTS value
 *
 * It loops through all items in CQP_COMMODITIES and their LIMITS,
 * and returns the PERCENTAGE where:
 *   MIN <= CQP_TOTAL_IMPORTS_ANNUAL_USD <= MAX
 *
 * @param none
 * @return (Number|0) matching percentage or 0 if not found
 *
 * by Adriana Centellas
 *******/

// 1) Get filtered commodities array
var filtered = this._parent.CQP_COMMODITIES_FILTERED || [];

// 2) Get the total imports value (convert to Number safely)
var total = this.CQP_TOTAL_STORAGE_PREMIUM_USD;

total = Number(total);

if (isNaN(total)) {
  return 0;
}

// 3) Search for the matching range in all LIMITS
for (var i = 0; i < filtered.length; i++) {
  var item = filtered[i];
  if (item.TYPE === 'STORAGE') {
    var limits = item && item.LIMITS ? item.LIMITS : [];

    for (var j = 0; j < limits.length; j++) {
      var band = limits[j];

      // Convert MIN and MAX to numbers (they come as strings)
      var min = Number(band.MIN);
      var max = Number(band.MAX);

      if (isNaN(min) || isNaN(max)) {
        continue; // skip invalid bands
      }

      // Check if total is within [MIN, MAX]
      if (total >= min && total <= max) {
        return band.PERCENTAGE; // found the matching percentage
      }
    }
  }
}

// 4) If no band matches, return null (or 0 if you prefer)
return 0;
